import { CommonModule } from "@angular/common";
import { Component, OnDestroy, OnInit, inject } from "@angular/core";
import { FormsModule } from "@angular/forms";
import { ActivatedRoute, Router, RouterLink } from "@angular/router";
import { StudentService } from "../../services/student.service";

@Component({
  selector: "app-student-quiz",
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: "./student-quiz.component.html",
  styleUrl: "./student-quiz.component.css"
})
export class StudentQuizComponent implements OnInit, OnDestroy {
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);
  private readonly studentService = inject(StudentService);
  private countdownRef: ReturnType<typeof setInterval> | null = null;

  quizData: any = null;
  loading = true;
  errorMessage = "";
  statusMessage = "";
  currentIndex = 0;
  remainingSeconds = 0;
  answers: Record<string, unknown> = {};
  result: any = null;
  submitting = false;
  courseId: number | null = null;

  get currentQuestion(): any {
    return this.quizData?.questions?.[this.currentIndex];
  }

  get isAllAtOnce(): boolean {
    return this.quizData?.displayMode === "ALL_AT_ONCE";
  }

  ngOnInit(): void {
    this.route.params.subscribe((params) => {
      const quizId = Number(params["quizId"]);
      if (!quizId) {
        this.router.navigateByUrl("/student/dashboard");
        return;
      }
      const courseIdParam = Number(this.route.snapshot.queryParamMap.get("courseId"));
      this.courseId = Number.isFinite(courseIdParam) && courseIdParam > 0 ? courseIdParam : null;
      this.startQuiz(quizId);
    });
  }

  ngOnDestroy(): void {
    this.clearTimer();
  }

  startQuiz(quizId: number): void {
    this.loading = true;
    this.errorMessage = "";
    this.result = null;
    this.statusMessage = "";
    this.answers = {};
    this.currentIndex = 0;
    this.studentService.startQuiz(quizId).subscribe({
      next: (data) => {
        this.quizData = data;
        this.loadSavedAnswers();
        this.remainingSeconds = data.timeLimitMinutes * 60;
        this.beginTimer();
        this.loading = false;
      },
      error: (error) => {
        const backendMessage = String(error?.error?.message ?? "");
        if (backendMessage.toLowerCase().includes("already answered")) {
          this.errorMessage = "Your quiz is already answered.";
        } else if (backendMessage.toLowerCase().includes("maximum attempts")) {
          this.errorMessage = "Your quiz is already answered (maximum attempts reached).";
        } else {
          this.errorMessage = backendMessage || "Unable to start quiz";
        }
        this.loading = false;
      }
    });
  }

  previousQuestion(): void {
    if (this.currentIndex > 0) {
      this.currentIndex--;
    }
  }

  nextQuestion(): void {
    if (this.currentIndex < this.quizData.questions.length - 1) {
      this.currentIndex++;
    }
  }

  goToQuestion(index: number): void {
    if (!this.quizData?.questions || index < 0 || index >= this.quizData.questions.length) {
      return;
    }
    this.currentIndex = index;
  }

  updateAnswer(questionId: number, value: unknown): void {
    this.answers[String(questionId)] = value;
    this.persistAnswers();
  }

  toggleMulti(questionId: number, option: string, checked: boolean): void {
    const key = String(questionId);
    const list = Array.isArray(this.answers[key]) ? [...(this.answers[key] as string[])] : [];
    const index = list.indexOf(option);
    if (checked && index === -1) {
      list.push(option);
    }
    if (!checked && index >= 0) {
      list.splice(index, 1);
    }
    this.answers[key] = list;
    this.persistAnswers();
  }

  updateMatching(questionId: number, left: string, selected: string): void {
    const key = String(questionId);
    const current = (this.answers[key] as Record<string, string> | undefined) ?? {};
    this.answers[key] = { ...current, [left]: selected };
    this.persistAnswers();
  }

  submitQuiz(force = false): void {
    if (!this.quizData || this.submitting || this.result) {
      return;
    }
    if (!force && !confirm("Submit quiz now?")) {
      return;
    }
    this.errorMessage = "";
    this.submitting = true;
    this.studentService.submitQuiz(this.quizData.quizId, {
      attemptId: this.quizData.attemptId,
      answers: this.answers
    }).subscribe({
      next: (data) => {
        this.result = data;
        this.statusMessage = "Your quiz has been answered successfully.";
        this.submitting = false;
        this.clearTimer();
        this.clearSavedAnswers();
      },
      error: (error) => {
        this.errorMessage = error?.error?.message ?? "Failed to submit quiz";
        this.submitting = false;
      }
    });
  }

  optionsArray(question: any): string[] {
    if (!question?.options) {
      return [];
    }
    if (Array.isArray(question.options)) {
      return question.options;
    }
    return [];
  }

  matchingLeft(question: any): string[] {
    const options = question?.options;
    if (!options || typeof options !== "object") {
      return [];
    }
    return Array.isArray(options.left) ? options.left : [];
  }

  matchingRight(question: any): string[] {
    const options = question?.options;
    if (!options || typeof options !== "object") {
      return [];
    }
    return Array.isArray(options.right) ? options.right : [];
  }

  answerText(questionId: number): string {
    const value = this.answers[String(questionId)];
    return typeof value === "string" ? value : "";
  }

  isMultiChecked(questionId: number, option: string): boolean {
    const value = this.answers[String(questionId)];
    return Array.isArray(value) && value.includes(option);
  }

  matchingValue(questionId: number, left: string): string {
    const value = this.answers[String(questionId)] as Record<string, string> | undefined;
    return value?.[left] ?? "";
  }

  timeLabel(): string {
    const min = Math.floor(this.remainingSeconds / 60).toString().padStart(2, "0");
    const sec = Math.floor(this.remainingSeconds % 60).toString().padStart(2, "0");
    return `${min}:${sec}`;
  }

  backRoute(): any[] {
    if (this.courseId) {
      return ["/student/courses", this.courseId];
    }
    return ["/student/dashboard"];
  }

  optionLabel(index: number): string {
    return String.fromCharCode(65 + index);
  }

  isQuestionAnswered(index: number): boolean {
    const question = this.quizData?.questions?.[index];
    if (!question) {
      return false;
    }
    const answer = this.answers[String(question.questionId)];
    if (question.questionType === "MULTI_SELECT") {
      return Array.isArray(answer) && answer.length > 0;
    }
    if (question.questionType === "MATCHING") {
      return !!answer && typeof answer === "object" && Object.keys(answer as Record<string, string>).length > 0;
    }
    return typeof answer === "string" && answer.trim().length > 0;
  }

  answeredCount(): number {
    if (!this.quizData?.questions) {
      return 0;
    }
    return this.quizData.questions.filter((_: any, index: number) => this.isQuestionAnswered(index)).length;
  }

  isCurrentLastQuestion(): boolean {
    return this.quizData?.questions ? this.currentIndex === this.quizData.questions.length - 1 : false;
  }

  allQuestions(): any[] {
    return this.quizData?.questions ?? [];
  }

  formatAnswer(value: unknown): string {
    if (value === null || value === undefined) {
      return "-";
    }
    if (typeof value === "string") {
      const trimmed = value.trim();
      return trimmed || "-";
    }
    if (Array.isArray(value)) {
      return value.map((item) => this.formatAnswer(item)).join(", ");
    }
    if (typeof value === "object") {
      return JSON.stringify(value);
    }
    return String(value);
  }

  private beginTimer(): void {
    this.clearTimer();
    this.countdownRef = setInterval(() => {
      this.remainingSeconds--;
      if (this.remainingSeconds <= 0) {
        this.remainingSeconds = 0;
        this.submitQuiz(true);
        this.clearTimer();
      }
    }, 1000);
  }

  private clearTimer(): void {
    if (this.countdownRef) {
      clearInterval(this.countdownRef);
      this.countdownRef = null;
    }
  }

  private persistAnswers(): void {
    if (!this.quizData?.attemptId) {
      return;
    }
    localStorage.setItem(this.storageKey(this.quizData.attemptId), JSON.stringify(this.answers));
  }

  private loadSavedAnswers(): void {
    if (!this.quizData?.attemptId) {
      return;
    }
    const raw = localStorage.getItem(this.storageKey(this.quizData.attemptId));
    if (!raw) {
      return;
    }
    try {
      this.answers = JSON.parse(raw);
    } catch {
      this.answers = {};
    }
  }

  private clearSavedAnswers(): void {
    if (!this.quizData?.attemptId) {
      return;
    }
    localStorage.removeItem(this.storageKey(this.quizData.attemptId));
  }

  private storageKey(attemptId: number): string {
    return `edusim-attempt-${attemptId}`;
  }
}
<div class="container">
  @if (loading) {
    <p>Preparing quiz...</p>
  } @else if (errorMessage) {
    <p class="error">{{ errorMessage }}</p>
    <a class="btn btn-outline" [routerLink]="backRoute()">Back</a>
  } @else if (quizData) {
    <a class="back-link" [routerLink]="backRoute()">&#8592; Back Course</a>
    @if (statusMessage) {
      <p class="ok">{{ statusMessage }}</p>
    }

    @if (result) {
      <section class="panel result">
        <h2>Quiz Submitted</h2>
        <p class="ok">Your quiz has been answered successfully.</p>
        @if (result.resultReleased) {
          <p class="score">Score: <strong>{{ result.score }}%</strong></p>
          <p>
            Status:
            <span class="badge" [class.fail]="!result.passed">
              {{ result.passed ? "PASS" : "FAIL" }}
            </span>
          </p>
          <p>Correct: {{ result.correctCount }}/{{ result.totalQuestions }}</p>
          <p>{{ result.feedback }}</p>
          @if (result.answers?.length) {
            <div class="result-review">
              <h3>Answer Review</h3>
              <div class="table-scroll">
                <table>
                  <thead>
                    <tr>
                      <th>Question</th>
                      <th>Your Answer</th>
                      <th>Correct Answer</th>
                      <th>Explanation</th>
                      <th>Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    @for (answer of result.answers; track answer.questionId) {
                      <tr [class.row-correct]="answer.correct" [class.row-wrong]="!answer.correct">
                        <td>{{ answer.prompt }}</td>
                        <td>{{ formatAnswer(answer.studentAnswer) }}</td>
                        <td>{{ formatAnswer(answer.correctAnswer) }}</td>
                        <td>{{ answer.explanation || "-" }}</td>
                        <td>
                          <span class="badge" [class.fail]="!answer.correct">
                            {{ answer.correct ? "Correct" : "Incorrect" }}
                          </span>
                        </td>
                      </tr>
                    }
                  </tbody>
                </table>
              </div>
            </div>
          }
        } @else {
          <p class="muted">Result is submitted and will be released by lecturer settings.</p>
          @if (result.releaseAt) {
            <p class="muted">Release time: {{ result.releaseAt | date: "medium" }}</p>
          }
        }
        <div class="result-actions">
          <a class="btn btn-outline" [routerLink]="backRoute()">Back Course</a>
          <a class="btn" routerLink="/student/history">View Attempt History</a>
        </div>
      </section>
    } @else {
      <section class="panel quiz-layout">
        <div class="quiz-main">
          <div class="quiz-heading">
            <h1>{{ quizData.title }}</h1>
            <p class="meta">Attempt {{ quizData.attemptNumber }} | {{ quizData.timeLimitMinutes }} minutes</p>
            <p class="meta">Due date: {{ quizData.closeAt ? (quizData.closeAt | date: "medium") : "Not set" }}</p>
            @if (quizData.description) {
              <p class="meta">{{ quizData.description }}</p>
            }
          </div>

          @if (isAllAtOnce) {
            <div class="all-questions">
              @for (question of allQuestions(); track question.questionId; let questionIndex = $index) {
                <section class="question-card">
                  <h2 class="question-title">Q{{ questionIndex + 1 }}. {{ question.prompt }}</h2>
                  @if (question.mediaUrl) {
                    <p class="media-line">Media ({{ question.mediaType || "link" }}): <a [href]="question.mediaUrl" target="_blank">{{ question.mediaUrl }}</a></p>
                  }

                  @if (question.questionType === "MCQ" || question.questionType === "TRUE_FALSE") {
                    <div class="answers">
                      @for (option of optionsArray(question); track option; let optionIndex = $index) {
                        <button
                          type="button"
                          class="option-btn"
                          [class.selected]="answerText(question.questionId) === option"
                          (click)="updateAnswer(question.questionId, option)">
                          <span class="option-tag">{{ optionLabel(optionIndex) }}</span>
                          <span>{{ option }}</span>
                        </button>
                      }
                    </div>
                  }

                  @if (question.questionType === "MULTI_SELECT") {
                    <div class="answers">
                      @for (option of optionsArray(question); track option) {
                        <label class="option-line">
                          <input
                            type="checkbox"
                            [checked]="isMultiChecked(question.questionId, option)"
                            (change)="toggleMulti(question.questionId, option, $any($event.target).checked)">
                          <span>{{ option }}</span>
                        </label>
                      }
                    </div>
                  }

                  @if (question.questionType === "SHORT_ANSWER") {
                    <textarea
                      rows="4"
                      [ngModel]="answerText(question.questionId)"
                      (ngModelChange)="updateAnswer(question.questionId, $event)"
                      placeholder="Type your answer..."></textarea>
                  }

                  @if (question.questionType === "MATCHING") {
                    <table>
                      <thead>
                        <tr>
                          <th>Left</th>
                          <th>Match With</th>
                        </tr>
                      </thead>
                      <tbody>
                        @for (left of matchingLeft(question); track left) {
                          <tr>
                            <td>{{ left }}</td>
                            <td>
                              <select
                                [ngModel]="matchingValue(question.questionId, left)"
                                (ngModelChange)="updateMatching(question.questionId, left, $event)">
                                <option value="">Select...</option>
                                @for (right of matchingRight(question); track right) {
                                  <option [value]="right">{{ right }}</option>
                                }
                              </select>
                            </td>
                          </tr>
                        }
                      </tbody>
                    </table>
                  }
                </section>
              }
            </div>

            <div class="actions">
              <button class="btn" type="button" [disabled]="submitting" (click)="submitQuiz()">
                {{ submitting ? "Submitting..." : "Submit Answer" }}
              </button>
            </div>
          } @else {
            <h2 class="question-title">Q{{ currentIndex + 1 }}. {{ currentQuestion.prompt }}</h2>
            @if (currentQuestion.mediaUrl) {
              <p class="media-line">Media ({{ currentQuestion.mediaType || "link" }}): <a [href]="currentQuestion.mediaUrl" target="_blank">{{ currentQuestion.mediaUrl }}</a></p>
            }

            @if (currentQuestion.questionType === "MCQ" || currentQuestion.questionType === "TRUE_FALSE") {
              <div class="answers">
                @for (option of optionsArray(currentQuestion); track option; let optionIndex = $index) {
                  <button
                    type="button"
                    class="option-btn"
                    [class.selected]="answerText(currentQuestion.questionId) === option"
                    (click)="updateAnswer(currentQuestion.questionId, option)">
                    <span class="option-tag">{{ optionLabel(optionIndex) }}</span>
                    <span>{{ option }}</span>
                  </button>
                }
              </div>
            }

            @if (currentQuestion.questionType === "MULTI_SELECT") {
              <div class="answers">
                @for (option of optionsArray(currentQuestion); track option) {
                  <label class="option-line">
                    <input
                      type="checkbox"
                      [checked]="isMultiChecked(currentQuestion.questionId, option)"
                      (change)="toggleMulti(currentQuestion.questionId, option, $any($event.target).checked)">
                    <span>{{ option }}</span>
                  </label>
                }
              </div>
            }

            @if (currentQuestion.questionType === "SHORT_ANSWER") {
              <textarea
                rows="5"
                [ngModel]="answerText(currentQuestion.questionId)"
                (ngModelChange)="updateAnswer(currentQuestion.questionId, $event)"
                placeholder="Type your answer..."></textarea>
            }

            @if (currentQuestion.questionType === "MATCHING") {
              <table>
                <thead>
                  <tr>
                    <th>Left</th>
                    <th>Match With</th>
                  </tr>
                </thead>
                <tbody>
                  @for (left of matchingLeft(currentQuestion); track left) {
                    <tr>
                      <td>{{ left }}</td>
                      <td>
                        <select
                          [ngModel]="matchingValue(currentQuestion.questionId, left)"
                          (ngModelChange)="updateMatching(currentQuestion.questionId, left, $event)">
                          <option value="">Select...</option>
                          @for (right of matchingRight(currentQuestion); track right) {
                            <option [value]="right">{{ right }}</option>
                          }
                        </select>
                      </td>
                    </tr>
                  }
                </tbody>
              </table>
            }

            <div class="actions">
              <button class="btn btn-outline" type="button" [disabled]="currentIndex === 0" (click)="previousQuestion()">
                Previous
              </button>
              <button class="btn btn-outline" type="button" [disabled]="isCurrentLastQuestion()" (click)="nextQuestion()">
                Next
              </button>
              <button class="btn" type="button" [disabled]="submitting" (click)="submitQuiz()">
                {{ submitting ? "Submitting..." : "Submit Answer" }}
              </button>
            </div>
          }
        </div>

        <aside class="quiz-side">
          <div class="timer-card">
            <div class="timer-circle" [class.critical]="remainingSeconds <= 60">{{ timeLabel() }}</div>
            <p>Timer remaining</p>
            <p class="answered">{{ answeredCount() }} / {{ quizData.questions.length }} answered</p>
          </div>

          @if (!isAllAtOnce) {
            <div class="question-list">
              @for (question of quizData.questions; track question.questionId; let i = $index) {
                <button
                  type="button"
                  class="question-item"
                  [class.current]="currentIndex === i"
                  [class.answered]="isQuestionAnswered(i)"
                  (click)="goToQuestion(i)">
                  <span>Question {{ i + 1 }}</span>
                  <span class="state">{{ isQuestionAnswered(i) ? "Answered" : "Pending" }}</span>
                </button>
              }
            </div>
          }
        </aside>
      </section>
    }
  }
</div>
